{
  "global": "Calculate the average kinetic energy of escaping nitrogen molecules by integrating the kinetic energy weighted by molecular flux over all velocity space.",
  "subtasks": [
    {
      "subtask": "Establish the Maxwell-Boltzmann velocity distribution for N₂ molecules at equilibrium temperature T",
      "atomics": [
        "Write the probability density function for velocity components in Cartesian coordinates",
        "Recognize that the distribution is isotropic for molecules in equilibrium"
      ]
    },
    {
      "subtask": "Determine the molecular flux through the small hole as a function of velocity",
      "atomics": [
        "Identify that molecular flux is proportional to the velocity component v_x normal to the hole surface",
        "Recognize that only molecules with v_x > 0 escape through the hole"
      ]
    },
    {
      "subtask": "Set up the integral for the average energy of escaping molecules",
      "atomics": [
        "Express the numerator as ∫∫∫ (1/2 m v²) v_x f(v) d³v for v_x > 0",
        "Express the denominator as ∫∫∫ v_x f(v) d³v for v_x > 0",
        "Note that the ratio gives the flux-weighted average kinetic energy"
      ]
    },
    {
      "subtask": "Evaluate the flux-weighted integrals using properties of Gaussian functions",
      "atomics": [
        "Factor the exponential in the Maxwell-Boltzmann distribution by velocity components",
        "Evaluate the integrals over v_y and v_z using standard Gaussian integral formulas",
        "Evaluate the remaining integrals over v_x using substitution u = v_x² and known results"
      ]
    },
    {
      "subtask": "Simplify the ratio to obtain the final expression",
      "atomics": [
        "Combine results from numerator and denominator integrals",
        "Recognize that mass and Boltzmann constant factors cancel",
        "Express the result as a multiple of k_B T"
      ]
    }
  ],
  "global_atomics": [
    "Verify dimensional consistency: result must have units of energy",
    "Compare with bulk average kinetic energy (3/2 k_B T) to confirm that escaping molecules carry more energy due to velocity selection"
  ],
  "gold_actions": {
    "global": "Compute [∫₀^∞ ∫_{-∞}^∞ ∫_{-∞}^∞ (1/2 m(v_x² + v_y² + v_z²)) v_x exp(-(m/2k_B T)(v_x² + v_y² + v_z²)) dv_x dv_y dv_z] / [∫₀^∞ ∫_{-∞}^∞ ∫_{-∞}^∞ v_x exp(-(m/2k_B T)(v_x² + v_y² + v_z²)) dv_x dv_y dv_z]",
    "subtasks": [
      {
        "subtask": "Write Maxwell-Boltzmann distribution",
        "atomics": [
          "Set f(v_x, v_y, v_z) = (m/2πk_B T)^(3/2) exp(-(m/2k_B T)(v_x² + v_y² + v_z²))",
          "Confirm isotropy ensures velocity distribution is independent of direction"
        ]
      },
      {
        "subtask": "Construct flux weighting function",
        "atomics": [
          "Multiply distribution by v_x to account for molecules hitting the hole proportional to their approach velocity",
          "Restrict integration to v_x ∈ [0, ∞) to include only escaping molecules"
        ]
      },
      {
        "subtask": "Evaluate flux-weighted integrals",
        "atomics": [
          "Factor and integrate over v_y and v_z: ∫_{-∞}^∞ exp(-av²) dv = √(π/a), yielding factor (2πk_B T/m) in denominator",
          "For numerator and denominator, evaluate ∫₀^∞ v_x^(2n+1) exp(-mv_x²/2k_B T) dv_x using n! factors from Gaussian integral family"
        ]
      },
      {
        "subtask": "Simplify ratio to extract temperature dependence",
        "atomics": [
          "Cancel m and k_B factors through algebraic simplification",
          "Recognize that (v_x² + v_y² + v_z²) terms with transverse components yield 2k_B T/m per component when weighted by v_x",
          "Sum contributions from all three directions to obtain E_avg = 2k_B T"
        ]
      }
    ],
    "global_atomics": [
      "Confirm result has dimensions [energy]: k_B [energy/temperature] × T [temperature] = [energy]",
      "Validate that 2k_B T exceeds bulk average of 3k_B T/2, reflecting selection bias toward high-velocity escape"
    ]
  }
}
